## 一、装饰器链（Decorator Chaining）

```python
@decorator_a
@decorator_b
@decorator_c
def func():
    pass

# 等价于
func = decorator_a(decorator_b(decorator_c(func)))
```

## 二、执行顺序（自下而上）

```python
def dec_a(func):
    def wrapper(*args, **kwargs):
        print("A 进入")
        result = func(*args, **kwargs)
        print("A 退出")
        return result
    return wrapper

def dec_b(func):
    def wrapper(*args, **kwargs):
        print("B 进入")
        result = func(*args, **kwargs)
        print("B 退出")
        return result
    return wrapper

@dec_a
@dec_b
def hello():
    print("Hello!")

hello()
# A 进入
# B 进入
# Hello!
# B 退出
# A 退出
```

## 三、实用案例：权限+日志+计时

```python
from functools import wraps
import time

def require_login(func):
    @wraps(func)
    def wrapper(user, *args, **kwargs):
        if not user.get("logged_in"):
            raise PermissionError("请先登录")
        return func(user, *args, **kwargs)
    return wrapper

def log_calls(func):
    @wraps(func)
    def wrapper(*args, **kwargs):
        print(f"[LOG] 调用 {func.__name__}({args}, {kwargs})")
        return func(*args, **kwargs)
    return wrapper

def timer(func):
    @wraps(func)
    def wrapper(*args, **kwargs):
        start = time.time()
        result = func(*args, **kwargs)
        print(f"[TIME] {func.__name__} 耗时 {time.time()-start:.3f}s")
        return result
    return wrapper

class User:
    def __init__(self, name, logged_in):
        self.name = name
        self.logged_in = logged_in

@timer
@log_calls
@require_login
def view_profile(user):
    print(f"{user.name} 的个人资料")
    return {"name": user.name}

user = User("Alice", True)
view_profile(user)
# [LOG] 调用 view_profile(({'name': 'Alice', 'logged_in': True},), {})
# Alice 的个人资料
# [TIME] view_profile 耗时 0.001s
```

## 四、带参数的装饰器链

```python
from functools import wraps

def retry(max_attempts=3, delay=0):
    def decorator(func):
        @wraps(func)
        def wrapper(*args, **kwargs):
            for attempt in range(1, max_attempts + 1):
                try:
                    return func(*args, **kwargs)
                except Exception as e:
                    if attempt == max_attempts:
                        raise
                    print(f"重试 {attempt}/{max_attempts}: {e}")
                    time.sleep(delay)
        return wrapper
    return decorator

def cache(func):
    cache_dict = {}
    @wraps(func)
    def wrapper(*args):
        if args not in cache_dict:
            cache_dict[args] = func(*args)
        return cache_dict[args]
    return wrapper

@retry(max_attempts=3, delay=1)
@cache
def unstable_api():
    import random
    if random.random() < 0.5:
        raise ValueError("API 临时失败")
    return "成功"

print(unstable_api())
```

## 五、类装饰器链

```python
class CountCalls:
    def __init__(self, func):
        wraps(func)(self)      # 让 CountCalls 实例伪装成 func
        self.func = func
        self.count = 0
    def __call__(self, *args, **kwargs):
        self.count += 1
        return self.func(*args, **kwargs)

def timer(cls):
    class Wrapped:
        def __init__(self, *args, **kwargs):
            self._instance = cls(*args, **kwargs)
        def __getattr__(self, name):
            attr = getattr(self._instance, name)
            if callable(attr):
                def timed(*args, **kwargs):
                    start = time.time()
                    result = attr(*args, **kwargs)
                    print(f"[{name}] 耗时 {time.time()-start:.3f}s")
                    return result
                return timed
            return attr
    return Wrapped

# 类装饰器（装饰一个类）
@timer
class MyService:
    def slow_method(self):
        time.sleep(0.5)
        return "done"

s = MyService()
s.slow_method()
# [slow_method] 耗时 0.500s
```

## 六、装饰器调试技巧

```python
# 1. 打印装饰器链
print(func)                    # 显示被装饰后的 wrapper
print(func.__wrapped__)        # 显示原函数

# 2. 用 attrs 排查
for attr in ["__name__", "__doc__", "__wrapped__"]:
    print(f"{attr}: {getattr(func, attr, 'NOT SET')}")

# 3. 调试断点打在 wrapper 里
